mapper.select:
/* getFromLocationStockInfo */
SELECT
	STOCKKY, WAREKEY, SKUMKEY, AREAKEY, LOCAKEY, LOLAYER
FROM
	${userData.schema}.WSTKKY
WHERE
	WAREKEY = #{param.warekey}
	AND AREAKEY = #{param.frareky}
	AND LOCAKEY = #{param.frlocky}
ORDER BY LOLAYER ASC

/* getToLocationStockInfo */
SELECT
	STOCKKY, WAREKEY, SKUMKEY, AREAKEY, LOCAKEY, LOLAYER
FROM
	${userData.schema}.WSTKKY
WHERE
	WAREKEY = #{param.warekey}
	AND AREAKEY = #{param.toareky}
	AND LOCAKEY = #{param.tolocky}
ORDER BY LOLAYER ASC

/* getLocationStockInfo */
SELECT
	STOCKKY, WAREKEY, SKUMKEY, AREAKEY, LOCAKEY, LOLAYER as STLAYER
	, 'N' as RMSTKYN, 'N' as RETUNYN
	, DATE_FORMAT(now(), '%y-%m-%d %H:%i:%s') as PHYDTTM
FROM
	${userData.schema}.WSTKKY
WHERE
	WAREKEY = #{param.warekey}
	AND AREAKEY = #{param.areakey}
	AND LOCAKEY = #{param.locakey}
ORDER BY LOLAYER ASC

mapper.update:
/* updateStockLayerSort */
UPDATE ${userData.schema}.WSTKKY
SET LOLAYER = #{param.lolayer},
	LMODATE = date_format(now(), '%Y%m%d'),
	LMOTIME = date_format(now(), '%H%i%s'),
	LMOUSER = #{userData.useract},
	UPDTCHK = UPDTCHK + 1
WHERE
	WAREKEY = #{param.warekey}
	AND STOCKKY = #{param.stockky}

mapper.select:
/* getEquipky */
SELECT
	EQUIPKY
FROM
	${userData.schema}.MEQLOC
WHERE
	WAREKEY = #{param.warekey}
	AND AREAKEY = #{param.toareky}
	AND LOCAKEY = #{param.tolocky}
ORDER BY MANEQYN DESC

LIMIT 1

/* getWstkkyList */ SELECT CONCAT(WS.STOCKKY, WS.WAREKEY) as ROWKEY , WS.STOCKKY, WS.WAREKEY, MW.WHNAMLC , WS.AREAKEY, MA.AREANAM , WS.LOCAKEY, ML.LOCANAM , WS.LOLAYER, WS.LOTNMKY, WS.OWNERKY, WS.OWNRNAM , WS.CUSTCOD, WS.CUSTNAM , WS.SKUGRKY, MGR.GRPKYNM, WS.SKUMKEY, WS.SKUDESC, WS.BTRFSTC , WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC , WS.GROSSWG, WS.GROSSWD, WS.GROSSLN, WS.GROSSTH , WS.BTRCATE, BC.BTRCNAM, WS.STLOTNB, WS.PURCNUM, WS.ORDERLN , WS.REGIORG, MR1.RENAMLC, WS.DESTORG, WS.DEORGNM , WS.REGIMOD, MR2.RENAMLC as REMODNM, WS.DESTMOD, WS.DEMODNM , WS.ITEMCOD, WS.STOTQTY, WS.TASKQTY, WS.SALLQTY, WS.SBLOQTY, WS.PLANQTY, WS.PLCMQTY , WS.SUOMKEY, WS.ADDCOKY, MC02.COMCDTX as ADDCONM, DATE_FORMAT(WS.RCVDCDT,'%Y-%m-%d') as RCVDCDT, DATE_FORMAT(STR_TO_DATE(WS.RCVDCTM,'%H%i%s'),'%H:%i:%s') as RCVDCTM , DATE_FORMAT(WS.SHPLIMT,'%Y-%m-%d') as SHPLIMT, DATE_FORMAT(WS.DELVDSR, '%Y-%m-%d') as DELVDSR , DATE_FORMAT(WS.POSHPDT,'%Y-%m-%d') as POSHPDT, DATE_FORMAT(STR_TO_DATE(WS.POSHPTM,'%H%i%s'),'%H:%i:%s') as POSHPTM, WS.POSHPDY , WS.DEMDMAN, WS.DEMDADR, WS.DEMDTLN , WS.LOTAT01, WS.LOTAT02, WS.LOTAT03 , WS.STKSTAT, MCO.COMCDTX as STATNAM, WS.STKMEMO, WS.EMSKUYN , WS.BLOCKID, WS.RCVDCKY , WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY , WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY , WS.TASKOIT , DATE_FORMAT(WS.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WS.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM( WS.CREUSER) AS CREUSER , DATE_FORMAT(WS.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WS.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER , WS.UPDTCHK , WS.DEMODNM, WS.DEMDMAN, WS.DEMDTLN, WS.DEMPOCD , WS.DEMDADR FROM ${userData.schema}.WSTKKY WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WS.WAREKEY AND MA.AREAKEY = WS.AREAKEY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = WS.WAREKEY AND ML.AREAKEY = WS.AREAKEY AND ML.LOCAKEY = WS.LOCAKEY AND ML.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MCO ON MCO.COMCDVL = WS.STKSTAT AND MCO.COMCDKY = 'STKSTAT' AND MCO.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MGR ON MGR.SKUGRKY = WS.SKUGRKY INNER JOIN ${userData.schema}.BADDCO BA ON BA.ADDCOKY = WS.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MC02 ON BA.ADDSIKY = MC02.COMCDVL AND MC02.COMCDKY = 'ADDSIKY' AND MC02.COUSEYN = 'Y' INNER JOIN ${userData.schema}.BTRCAT BC ON BC.BTRCATE = WS.BTRCATE WHERE WS.WAREKEY = #{param.warekey} AND WS.STOTQTY > 0 AND WS.TASKQTY = 0 AND WS.SALLQTY = 0 AND WS.PLANQTY = 0 AND WS.PLCMQTY = 0
AND WS.AREAKEY = #{param.areakey}
AND WS.LOCAKEY IN
#{locakey}
AND WS.SKUMKEY IN
#{skumkey}
AND WS.SKUMKEY LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND WS.ORDERLN IN
#{orderln}
AND WS.ORDERLN LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND WS.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
AND WS.PURCNUM LIKE CONCAT('%',#{param.purcnum},'%')
AND WS.REGIMOD IN
#{regikey}
AND WS.DEMODNM LIKE CONCAT('%',#{param.demodnm},'%')
ORDER BY WS.AREAKEY, WS.LOCAKEY, WS.LOLAYER DESC, WS.EMSKUYN DESC

/* checkDoe035StockVail */
SELECT
	COUNT(1)
FROM
	${userData.schema}.WSTKKY
WHERE
	WAREKEY = #{param.warekey}
	AND STOCKKY = #{param.stockky}
	AND UPDTCHK = #{param.updtchk}

	/* checkDoe035AboveStockExist */
	SELECT
		COUNT(1)
	FROM
		${userData.schema}.WSTKKY WS

		LEFT JOIN (
			SELECT
				STOCKKY, LOLAYER
			FROM
				${userData.schema}.WSTKKY
			WHERE
				WAREKEY = #{param.warekey}
				AND AREAKEY = #{param.areakey}
				AND LOCAKEY = #{param.locakey}
				AND LOLAYER IN

                    #{layer}

		) WST
		ON WST.STOCKKY = WS.STOCKKY

	WHERE
		WS.WAREKEY = #{param.warekey}
		AND WS.AREAKEY = #{param.areakey}
		AND WS.LOCAKEY = #{param.locakey}
		AND WS.LOLAYER >  #{param.lolayer}

			AND WST.LOLAYER IS NULL

	/* checkDoe035AboveTaskExist */
	SELECT
		COUNT(1)
	FROM
		${userData.schema}.WSTKKY WS
	INNER JOIN ${userData.schema}.WTAKIT WT
		ON WT.TASKOKY = WS.TASKOKY
		AND WT.TASKOIT = WS.TASKOIT
		AND WT.DOCCATE = '500'
		AND WT.TASKSTS NOT IN ('CMP', 'CANCEL')

		LEFT JOIN (
			SELECT
				STOCKKY, LOLAYER
			FROM
				${userData.schema}.WSTKKY
			WHERE
				WAREKEY = #{param.warekey}
				AND AREAKEY = #{param.areakey}
				AND LOCAKEY = #{param.locakey}
				AND LOLAYER IN

                    #{layer}

		) WST
		ON WST.STOCKKY = WS.STOCKKY

	WHERE
		WS.WAREKEY = #{param.warekey}
		AND WS.AREAKEY = #{param.areakey}
		AND WS.LOCAKEY = #{param.locakey}
		AND WS.LOLAYER >  #{param.lolayer}

			AND WST.LOLAYER IS NULL

/* checkDoe035StockAboveOutExist */
SELECT
	COUNT(1)
FROM
	${userData.schema}.WPLNIT
WHERE
	WAREKEY = #{param.warekey}
	AND STOCKKY = #{param.stockky}
	AND WPLITST = 'ING'

/* getDoe035WstkkyList */ SELECT CONCAT(WS.STOCKKY, WS.WAREKEY) as ROWKEY , WS.STOCKKY, WS.WAREKEY, MW.WHNAMLC , WS.AREAKEY, MA.AREANAM , WS.LOCAKEY, ML.LOCANAM , WS.LOLAYER, WS.LOTNMKY, WS.OWNERKY, WS.OWNRNAM , WS.CUSTCOD, WS.CUSTNAM , WS.SKUGRKY, MGR.GRPKYNM, WS.SKUMKEY, WS.SKUDESC, WS.BTRFSTC , WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC , WS.GROSSWG, WS.GROSSWD, WS.GROSSLN, WS.GROSSTH , WS.BTRCATE, BC.BTRCNAM, WS.STLOTNB, WS.PURCNUM, WS.ORDERLN , WS.REGIORG, MR1.RENAMLC, WS.DESTORG, WS.DEORGNM , WS.REGIMOD, MR2.RENAMLC as REMODNM, WS.DESTMOD, WS.DEMODNM , WS.ITEMCOD, WS.STOTQTY, WS.TASKQTY, WS.SALLQTY, WS.SBLOQTY, WS.PLANQTY, WS.PLCMQTY , WS.SUOMKEY, WS.ADDCOKY, MC02.COMCDTX as ADDCONM, DATE_FORMAT(WS.RCVDCDT,'%Y-%m-%d') as RCVDCDT , WS.LOTAT01, WS.LOTAT02, WS.LOTAT03 , WS.STKSTAT, MCO.COMCDTX as STATNAM, WS.STKMEMO, WS.EMSKUYN , WS.BLOCKID, WS.RCVDCKY , WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY , WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY , WS.TASKOIT , DATE_FORMAT(WS.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WS.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM( WS.CREUSER) AS CREUSER , DATE_FORMAT(WS.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WS.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER , WS.UPDTCHK , WS.DEMODNM, WS.DEMDMAN, WS.DEMDTLN , CASE WHEN (WS.DEMDADR IS NULL OR WS.DEMDADR = '') AND (WS.DEMPOCD IS NULL OR WS.DEMPOCD = '') THEN '' WHEN (WS.DEMPOCD IS NULL OR WS.DEMPOCD = '') AND (WS.DEMDADR IS NOT NULL OR WS.DEMDADR != '') THEN WS.DEMDADR ELSE CONCAT('(', WS.DEMPOCD, ') ', WS.DEMDADR) END AS DEMDADR FROM ${userData.schema}.WSTKKY WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WS.WAREKEY AND MA.AREAKEY = WS.AREAKEY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = WS.WAREKEY AND ML.AREAKEY = WS.AREAKEY AND ML.LOCAKEY = WS.LOCAKEY AND ML.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MCO ON MCO.COMCDVL = WS.STKSTAT AND MCO.COMCDKY = 'STKSTAT' AND MCO.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MGR ON MGR.SKUGRKY = WS.SKUGRKY INNER JOIN ${userData.schema}.BADDCO BA ON BA.ADDCOKY = WS.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MC02 ON BA.ADDSIKY = MC02.COMCDVL AND MC02.COMCDKY = 'ADDSIKY' AND MC02.COUSEYN = 'Y' INNER JOIN ${userData.schema}.BTRCAT BC ON BC.BTRCATE = WS.BTRCATE WHERE WS.WAREKEY = #{param.warekey} AND WS.STOTQTY > 0 AND WS.TASKQTY = 0 AND WS.PLCMQTY = 0
AND WS.AREAKEY = #{param.areakey}
AND WS.LOCAKEY IN
#{locakey}
AND WS.SKUMKEY IN
#{skumkey}
AND WS.SKUMKEY LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND WS.ORDERLN IN
#{orderln}
AND WS.ORDERLN LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND WS.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
AND WS.PURCNUM LIKE CONCAT('%',#{param.purcnum},'%')
AND WS.REGIMOD IN
#{regikey}
AND WS.DEMODNM LIKE CONCAT('%',#{param.demodnm},'%')
ORDER BY WS.AREAKEY, WS.LOCAKEY, WS.LOLAYER DESC, WS.EMSKUYN DESC

mapper.insert:
INSERT INTO ${userData.schema}.WTAKIT(
	TASKOKY, TASKOIT, WAREKEY
	, TASKDAT, DOCCATE, DOCTYPE, TASKSTS
	, LOTNMKY, OWNERKY, OWNRNAM, CUSTCOD, CUSTNAM
	, SKUMKEY, SKUDESC
	, FRAREKY, FRLOCKY, FRLAYER
	, TOAREKY, TOLOCKY, TOLAYER
	, EQUIPKY
	, FORDQTY
	, STOCKKY
	, PARSNCD, PARSNNM
	, CREDATE, CRETIME, CREUSER
	, LMODATE, LMOTIME, LMOUSER
)
VALUES(
	#{param.taskoky}, #{param.taskoit}, #{param.warekey}
	, date_format(now(), '%Y%m%d'), #{param.doccate}, #{param.doctype}, #{param.tasksts}
	, #{param.lotnmky}, #{param.ownerky}, #{param.ownrnam}, #{param.custcod}, #{param.custnam}
	, #{param.skumkey}, #{param.skudesc}
	, #{param.areakey}, #{param.locakey}, #{param.lolayer}
	, #{param.toareky}, #{param.tolocky}, #{param.tolayer}
	, #{param.equipky}
	, #{param.stotqty}
	, #{param.stockky}
	, #{param.parsncd}, #{param.parsnnm}
	, date_format(now(), '%Y%m%d'), date_format(now(), '%H%i%s'), #{userData.useract}
	, date_format(now(), '%Y%m%d'), date_format(now(), '%H%i%s'), #{userData.useract}
)

mapper.select:
/* getDoeDy035WstkkyList */ SELECT CONCAT(WS.STOCKKY, WS.WAREKEY) as ROWKEY , WS.STOCKKY, WS.WAREKEY, MW.WHNAMLC , WS.AREAKEY, MA.AREANAM , WS.LOCAKEY, ML.LOCANAM , WS.LOLAYER, WS.LOTNMKY, WS.OWNERKY, WS.OWNRNAM , WS.CUSTCOD, WS.CUSTNAM , WS.SKUGRKY, MGR.GRPKYNM, WS.SKUMKEY, WS.SKUDESC, WS.BTRFSTC , WS.SKUWEIG, WS.SKUWIDT, WS.SKULENG, WS.SKUTHIC , WS.GROSSWG, WS.GROSSWD, WS.GROSSLN, WS.GROSSTH , WS.BTRCATE, BC.BTRCNAM, WS.STLOTNB, WS.PURCNUM, WS.ORDERLN , WS.REGIORG, MR1.RENAMLC, WS.DESTORG, WS.DEORGNM , WS.REGIMOD, MR2.RENAMLC as REMODNM, WS.DESTMOD, WS.DEMODNM , WS.ITEMCOD, WS.STOTQTY, WS.TASKQTY, WS.SALLQTY, WS.SBLOQTY, WS.PLANQTY, WS.PLCMQTY , WS.SUOMKEY, WS.ADDCOKY, MC02.COMCDTX as ADDCONM, DATE_FORMAT(WS.RCVDCDT,'%Y-%m-%d') as RCVDCDT , WS.LOTAT01, WS.LOTAT02, WS.LOTAT03 , WS.STKSTAT, MCO.COMCDTX as STATNAM, WS.STKMEMO, WS.EMSKUYN , WS.BLOCKID, WS.RCVDCKY , WS.RCVDCIT, WS.ADJSOKY, WS.ADJSOIT, WS.PHYSOKY , WS.PHYSOIT, WS.SHPDCKY, WS.SHPDCIT, WS.TASKOKY , WS.TASKOIT , DATE_FORMAT(WS.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WS.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM( WS.CREUSER) AS CREUSER , DATE_FORMAT(WS.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WS.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WS.LMOUSER) AS LMOUSER , WS.UPDTCHK , WS.DEMODNM, WS.DEMDMAN, WS.DEMDTLN , CASE WHEN (WS.DEMDADR IS NULL OR WS.DEMDADR = '') AND (WS.DEMPOCD IS NULL OR WS.DEMPOCD = '') THEN '' WHEN (WS.DEMPOCD IS NULL OR WS.DEMPOCD = '') AND (WS.DEMDADR IS NOT NULL OR WS.DEMDADR != '') THEN WS.DEMDADR ELSE CONCAT('(', WS.DEMPOCD, ') ', WS.DEMDADR) END AS DEMDADR FROM ${userData.schema}.WSTKKY WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WS.WAREKEY AND MA.AREAKEY = WS.AREAKEY AND MA.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = WS.WAREKEY AND ML.AREAKEY = WS.AREAKEY AND ML.LOCAKEY = WS.LOCAKEY AND ML.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MCO ON MCO.COMCDVL = WS.STKSTAT AND MCO.COMCDKY = 'STKSTAT' AND MCO.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MGR ON MGR.SKUGRKY = WS.SKUGRKY INNER JOIN ${userData.schema}.BADDCO BA ON BA.ADDCOKY = WS.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MC02 ON BA.ADDSIKY = MC02.COMCDVL AND MC02.COMCDKY = 'ADDSIKY' AND MC02.COUSEYN = 'Y' INNER JOIN ${userData.schema}.BTRCAT BC ON BC.BTRCATE = WS.BTRCATE WHERE WS.WAREKEY = #{param.warekey}
AND WS.PLCMQTY = 0
AND WS.AREAKEY = #{param.areakey}
AND WS.LOCAKEY IN
#{locakey}
AND WS.SKUMKEY IN
#{skumkey}
AND WS.SKUMKEY LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND WS.ORDERLN IN
#{orderln}
AND WS.ORDERLN LIKE CONCAT('%', UPPER(TRIM(#{param.orderln})), '%')
AND WS.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
AND WS.PURCNUM LIKE CONCAT('%',#{param.purcnum},'%')
AND WS.REGIMOD IN
#{regikey}
AND WS.DEMODNM LIKE CONCAT('%',#{param.demodnm},'%')
ORDER BY WS.AREAKEY, WS.LOCAKEY, WS.LOLAYER DESC, WS.EMSKUYN DESC

/* getDoe036HeadList */ SELECT CONCAT(WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.TASKOKY, COUNT(WT.TASKOIT) as TSITCNT , WT.WAREKEY, MW.WHNAMLC , DATE_FORMAT(WT.TASKDAT,'%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , MIN(WT.TASKSTS) as TASKSTS, MC.COMCDTX as TSTSNAM , WT.EQUIPKY, MEQ.EQUINAM, MEQ.AREAKEY, MA.AREANAM , DATE_FORMAT( WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) AS CREUSER , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER) AS LMOUSER , WT.UPDTCHK FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ( SELECT TASKOKY, MIN(TASKSTS) as TASKSTS FROM ${userData.schema}.WTAKIT GROUP BY TASKOKY ) T ON T.TASKOKY = WT.TASKOKY INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = T.TASKSTS AND MC.COMCDKY = 'TASKSTS' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WT.WAREKEY AND MR.DOCCATE = WT.DOCCATE AND MR.DOCTYPE = WT.DOCTYPE AND MR.RSNCODE = WT.PARSNCD AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.MEQUMA MEQ ON MEQ.WAREKEY = WT.WAREKEY AND MEQ.AREAKEY = WT.TOAREKY AND MEQ.EQUIPKY = WT.EQUIPKY INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = MEQ.WAREKEY AND MA.AREAKEY = MEQ.AREAKEY WHERE WT.WAREKEY = #{param.warekey}
AND WT.DOCTYPE = #{param.doctype}
AND WT.TASKSTS IN
#{tasksts}
AND WT.EQUIPKY = #{param.equipky}
AND WT.SKUMKEY = #{param.skumkey}
AND WT.TASKOKY LIKE CONCAT('%',#{param.taskoky},'%')
AND WS.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
GROUP BY WT.TASKOKY, WT.WAREKEY, MW.WHNAMLC, WT.DOCCATE, WT.EQUIPKY, MEQ.EQUINAM , MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM, MEQ.AREAKEY, MA.AREANAM ORDER BY WT.TASKOKY DESC

/* getDoe036ItemList */ SELECT CONCAT(WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.TASKOKY, WT.TASKOIT , WT.WAREKEY, MW.WHNAMLC , DATE_FORMAT(WT.TASKDAT,'%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.TASKSTS, MC.COMCDTX as TSTSNAM, WT.LOTNMKY , WT.OWNERKY, WT.OWNRNAM, WT.CUSTCOD, WT.CUSTNAM , WT.SKUMKEY, WT.SKUDESC, WT.EQUIPKY, ME.EQUINAM , WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY, WS.PLANQTY, WS.PLCMQTY , WT.FRAREKY, MA1.AREANAM as FRARANM, WT.FRLOCKY, ML1.LOCANAM as FRLOCNM, WT.FRLAYER , WT.TOAREKY, MA2.AREANAM as TOARANM, WT.TOLOCKY, ML2.LOCANAM as TOLOCNM , WS.REGIORG, MR1.RENAMLC AS RGORGNM, WS.DESTORG, WS.DEORGNM , WS.REGIMOD, MR2.RENAMLC AS RGMODNM, WS.DESTMOD, WS.DEMODNM , WT.FORDQTY, WT.TCMPQTY, WT.ALLGRKY , WT.MVSTDAT, WT.MVSTTIM , WT.MVEDDAT, WT.MVEDTIM , WT.PARSNCD, MR.RSNCDNM, WT.PARSNNM , WT.PKRSNCD, WT.PKRSNNM , WT.STOCKKY, WS.EMSKUYN, WS.STKMEMO , WT.EOASNKY, WT.EOASNIT , WT.COSTRKY, WT.COSTRIT , WT.RCVDCKY, WT.RCVDCIT , WT.OUTBOKY, WT.OUTBOIT , WT.SHPDCKY, WT.SHPDCIT , DATE_FORMAT( WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) AS CREUSER , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER) AS LMOUSER , WT.UPDTCHK FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WT.TASKSTS AND MC.COMCDKY = 'TASKSTS' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA1 ON MA1.WAREKEY = WT.WAREKEY AND MA1.AREAKEY = WT.FRAREKY AND MA1.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA2 ON MA2.WAREKEY = WT.WAREKEY AND MA2.AREAKEY = WT.TOAREKY AND MA2.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WT.WAREKEY AND ML1.AREAKEY = WT.FRAREKY AND ML1.LOCAKEY = WT.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WT.WAREKEY AND ML2.AREAKEY = WT.TOAREKY AND ML2.LOCAKEY = WT.TOLOCKY AND ML2.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WT.WAREKEY AND MR.DOCCATE = WT.DOCCATE AND MR.DOCTYPE = WT.DOCTYPE AND MR.RSNCODE = WT.PARSNCD AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.WSTKKY WS ON WS.WAREKEY = WT.WAREKEY AND WS.STOCKKY = WT.STOCKKY INNER JOIN ${userData.schema}.MEQUMA ME ON ME.EQUIPKY = WT.EQUIPKY INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' WHERE WT.WAREKEY = #{param.warekey}
AND WT.EQUIPKY IN
#{equipky}
AND WT.TASKSTS IN
#{tasksts}
AND WT.TASKOKY LIKE CONCAT('%',#{param.taskoky},'%')
AND WS.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
AND WS.REGIMOD IN
#{regikey}
