/* getDoe036WtakitTaskstsList */ SELECT CONCAT(WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.TASKOKY, WT.TASKOIT , WT.WAREKEY, MW.WHNAMLC , DATE_FORMAT(WT.TASKDAT,'%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.TASKSTS, MC.COMCDTX as TSTSNAM, WT.LOTNMKY , WT.OWNERKY, WT.OWNRNAM, WT.CUSTCOD, WT.CUSTNAM , WT.SKUMKEY, WT.SKUDESC , WT.FRAREKY, MA1.AREANAM as FRARANM, WT.FRLOCKY, ML1.LOCANAM as FRLOCNM, WT.FRLAYER , WT.TOAREKY, MA2.AREANAM as TOARANM, WT.TOLOCKY, ML2.LOCANAM as TOLOCNM, WT.TOLAYER , WT.FORDQTY, WT.TCMPQTY, WT.ALLGRKY , WT.MVSTDAT, WT.MVSTTIM , WT.MVEDDAT, WT.MVEDTIM , WT.PARSNCD, MR.RSNCDNM, WT.PARSNNM , WT.PKRSNCD, WT.PKRSNNM , WT.STOCKKY , WT.EOASNKY, WT.EOASNIT , WT.COSTRKY, WT.COSTRIT , WT.RCVDCKY, WT.RCVDCIT , WT.OUTBOKY, WT.OUTBOIT , WT.SHPDCKY, WT.SHPDCIT , DATE_FORMAT( WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) AS CREUSER , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER) AS LMOUSER , WT.UPDTCHK FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WT.TASKSTS AND MC.COMCDKY = 'TASKSTS' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA1 ON MA1.WAREKEY = WT.WAREKEY AND MA1.AREAKEY = WT.FRAREKY AND MA1.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA2 ON MA2.WAREKEY = WT.WAREKEY AND MA2.AREAKEY = WT.TOAREKY AND MA2.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WT.WAREKEY AND ML1.AREAKEY = WT.FRAREKY AND ML1.LOCAKEY = WT.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WT.WAREKEY AND ML2.AREAKEY = WT.TOAREKY AND ML2.LOCAKEY = WT.TOLOCKY AND ML2.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WT.WAREKEY AND MR.DOCCATE = WT.DOCCATE AND MR.DOCTYPE = WT.DOCTYPE AND MR.RSNCODE = WT.PARSNCD AND MR.RSUSEYN = 'Y' LEFT JOIN ${userData.schema}.WSTKKY WS ON WS.WAREKEY = WT.WAREKEY AND WS.STOCKKY = WT.STOCKKY WHERE WT.WAREKEY = #{param.warekey} AND WT.TASKOKY = #{param.taskoky}
AND WT.TASKSTS IN
#{tasksts}

/* getDoe036StockInfos */ SELECT CONCAT(WS.SKUMKEY, WS.TASKOIT) as ROWKEY , WS.SKUMKEY, WS.WAREKEY, WS.AREAKEY AS FRAREKY, WS.LOCAKEY AS FRLOCKY , WS.LOLAYER AS FRLAYER, WT.TASKOKY
, MW.WHNAMLC AS WHNAMLC , MA2.AREANAM AS TOARANM, ML2.LOCAKEY AS TOLOCKY, ML2.LOCANAM AS TOLOCNM , MA1.AREANAM AS FRARANM, ML1.LOCANAM AS FRLOCNM, MA2.AREAKEY AS TOAREKY , WT.TOAREKY, WT.STOCKKY, WT.TASKOIT, WT.EQUIPKY , WSI.SHPDCKY, WSI.SHPDCIT
, WS.CREDATE, WS.CRETIME, WS.CREUSER, WS.LMODATE, WS.LMOTIME, WS.LMOUSER, WT.UPDTCHK FROM ${userData.schema}.WSTKKY WS INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WS.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA1 ON MA1.WAREKEY = WS.WAREKEY AND MA1.AREAKEY = WS.AREAKEY AND MA1.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WS.WAREKEY AND ML1.AREAKEY = WS.AREAKEY AND ML1.LOCAKEY = WS.LOCAKEY AND ML1.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.WTAKIT WT ON WT.STOCKKY = WS.STOCKKY AND WT.SKUMKEY = WS.SKUMKEY AND WT.WAREKEY = WS.WAREKEY AND WT.FRAREKY = WS.AREAKEY AND WT.FRLOCKY = WS.LOCAKEY AND WT.TASKSTS NOT IN ('CMP') LEFT JOIN ${userData.schema}.MAREMA MA2 ON MA2.WAREKEY = WT.WAREKEY AND MA2.AREAKEY = WT.TOAREKY AND MA2.ARUSEYN = 'Y' LEFT JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WT.WAREKEY AND ML2.AREAKEY = WT.TOAREKY AND ML2.LOCAKEY = WT.TOLOCKY AND ML2.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.WSHPIT WSI ON WSI.SKUMKEY = WS.SKUMKEY AND WSI.WAREKEY = WS.WAREKEY AND WSI.FRAREKY = WS.AREAKEY AND WSI.FRLOCKY = WS.LOCAKEY AND WSI.SHPITST NOT IN ('CMP') WHERE WS.WAREKEY = #{param.warekey}
AND WS.AREAKEY = #{param.frareky}
AND WS.LOCAKEY = #{param.frlocky}
ORDER BY WS.LOLAYER DESC

/* getDoe037WtakitList */ SELECT CONCAT(WT.TASKOKY, WT.TASKOIT) as ROWKEY , WT.TASKOKY, WT.TASKOIT , WT.WAREKEY, MW.WHNAMLC , DATE_FORMAT(WT.TASKDAT,'%Y-%m-%d') as TASKDAT , WT.DOCCATE, MD.DOCCTNM, WT.DOCTYPE, MD.DOCTYNM , WT.TASKSTS, WT.LOTNMKY , WT.OWNERKY, WT.OWNRNAM, WT.CUSTCOD, WT.CUSTNAM , WT.SKUMKEY, WT.SKUDESC, WT.EQUIPKY, ME.EQUINAM , WS.STOTQTY, WS.SALLQTY, WS.SBLOQTY, WS.PLANQTY, WS.PLCMQTY , WT.FRAREKY, MA1.AREANAM as FRARANM, WT.FRLOCKY, ML1.LOCANAM as FRLOCNM, WT.FRLAYER , WT.TOAREKY, MA2.AREANAM as TOARANM, WT.TOLOCKY, ML2.LOCANAM as TOLOCNM, WT.TOLAYER , WS.REGIORG, MR1.RENAMLC AS RGORGNM, WS.DESTORG, WS.DEORGNM , WS.REGIMOD, MR2.RENAMLC AS RGMODNM, WS.DESTMOD, WS.DEMODNM , WT.FORDQTY, WT.TCMPQTY, WT.ALLGRKY , WT.MVSTDAT, WT.MVSTTIM , WT.MVEDDAT, WT.MVEDTIM , WS.ADDCOKY , WS.BTRCATE, BC.BTRCNAM , WT.PARSNCD, MR.RSNCDNM, WT.PARSNNM , WT.PKRSNCD, WT.PKRSNNM , WT.STOCKKY, WS.EMSKUYN, WS.STKMEMO , WT.EOASNKY, WT.EOASNIT , WT.COSTRKY, WT.COSTRIT , WT.RCVDCKY, WT.RCVDCIT , WT.OUTBOKY, WT.OUTBOIT , WT.SHPDCKY, WT.SHPDCIT , DATE_FORMAT( WT.CREDATE,'%Y-%m-%d') as CREDATE , DATE_FORMAT(STR_TO_DATE(WT.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(WT.CREUSER) AS CREUSER , DATE_FORMAT(WT.LMODATE,'%Y-%m-%d') as LMODATE , DATE_FORMAT(STR_TO_DATE(WT.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(WT.LMOUSER) AS LMOUSER , WT.UPDTCHK , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'TASKSTS' AND COMCDVL = WT.TASKSTS AND COUSEYN = 'Y') AS TSTSNAM , (SELECT COMCDTX FROM ${userData.schema}.MCODEM WHERE COMCDKY = 'ADDSIKY' AND COMCDVL = BA.ADDSIKY AND COUSEYN = 'Y') AS ADDCONM FROM ${userData.schema}.WTAKIT WT INNER JOIN ${userData.schema}.MWARMA MW ON MW.WAREKEY = WT.WAREKEY AND MW.WHUSEYN = 'Y' INNER JOIN ${userData.schema}.MDOCMA MD ON MD.WAREKEY = WT.WAREKEY AND MD.DOCCATE = WT.DOCCATE AND MD.DOCTYPE = WT.DOCTYPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA1 ON MA1.WAREKEY = WT.WAREKEY AND MA1.AREAKEY = WT.FRAREKY AND MA1.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MAREMA MA2 ON MA2.WAREKEY = WT.WAREKEY AND MA2.AREAKEY = WT.TOAREKY AND MA2.ARUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML1 ON ML1.WAREKEY = WT.WAREKEY AND ML1.AREAKEY = WT.FRAREKY AND ML1.LOCAKEY = WT.FRLOCKY AND ML1.LOUSEYN = 'Y' INNER JOIN ${userData.schema}.MLOCMA ML2 ON ML2.WAREKEY = WT.WAREKEY AND ML2.AREAKEY = WT.TOAREKY AND ML2.LOCAKEY = WT.TOLOCKY AND ML2.LOUSEYN = 'Y' LEFT JOIN ${userData.schema}.MRSCMA MR ON MR.WAREKEY = WT.WAREKEY AND MR.DOCCATE = WT.DOCCATE AND MR.DOCTYPE = WT.DOCTYPE AND MR.RSNCODE = WT.PARSNCD AND MR.RSUSEYN = 'Y' INNER JOIN ${userData.schema}.WSTKKY WS ON WS.WAREKEY = WT.WAREKEY AND WS.STOCKKY = WT.STOCKKY INNER JOIN ${userData.schema}.BADDCO BA ON BA.ADDCOKY = WS.ADDCOKY INNER JOIN ${userData.schema}.BTRCAT BC ON BC.BTRCATE = WS.BTRCATE INNER JOIN ${userData.schema}.MGRPMA MGR ON MGR.SKUGRKY = WS.SKUGRKY INNER JOIN ${userData.schema}.MEQUMA ME ON ME.EQUIPKY = WT.EQUIPKY INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WS.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WS.REGIMOD AND MR2.REUSEYN = 'Y' WHERE WT.WAREKEY = #{param.warekey} AND WT.DOCCATE = '500'
AND WT.TASKSTS IN
#{tasksts}
AND WT.SKUMKEY IN
#{skumkey}
AND WT.SKUMKEY LIKE CONCAT('%', UPPER(TRIM(#{param.skumkey})), '%')
AND WT.EQUIPKY IN
#{equipky}
AND WT.TASKSTS IN
#{tasksts}
AND WT.TASKOKY LIKE CONCAT('%',#{param.taskoky},'%')
AND WS.CUSTNAM LIKE CONCAT('%',#{param.custnam},'%')
AND WS.REGIMOD IN
#{regikey}
AND DATE_FORMAT(STR_TO_DATE(WT.TASKDAT, '%Y%m%d'), '%Y-%m-%d') >= #{param.taskdatfrom}
AND DATE_FORMAT(STR_TO_DATE(WT.TASKDAT, '%Y%m%d'), '%Y-%m-%d') <= #{param.taskdatto}
AND WS.DEMODNM LIKE CONCAT('%',#{param.demodnm},'%')
ORDER BY WT.TASKOKY DESC, WT.FRAREKY, WT.FRLAYER DESC

