YPE AND MD.DOUSEYN = 'Y' INNER JOIN ${userData.schema}.MCODEM MC ON MC.COMCDVL = WP.PHYSTAT AND MC.COMCDKY = 'PHYSTAT' AND MC.COUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR1 ON MR1.REGIKEY = WP.REGIORG AND MR1.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MREGMA MR2 ON MR2.REGIKEY = WP.REGIMOD AND MR2.REUSEYN = 'Y' INNER JOIN ${userData.schema}.MGRPMA MGR ON MGR.SKUGRKY = WP.SKUGRKY INNER JOIN ${userData.schema}.MAREMA MA ON MA.WAREKEY = WP.WAREKEY AND MA.AREAKEY = WP.AREAKEY INNER JOIN ${userData.schema}.MLOCMA ML ON ML.WAREKEY = WP.WAREKEY AND ML.AREAKEY = WP.AREAKEY AND ML.LOCAKEY = WP.LOCAKEY INNER JOIN ${userData.schema}.BADDCO BA ON BA.ADDCOKY = WP.ADDCOKY INNER JOIN ${userData.schema}.MCODEM MC2 ON MC2.COMCDVL = BA.ADDSIKY AND MC2.COMCDKY = 'ADDSIKY' AND MC2.COUSEYN = 'Y' INNER JOIN ${userData.schema}.BTRCAT BT ON BT.BTRCATE = WP.BTRCATE WHERE WP.WAREKEY = #{param.warekey} AND WP.PHYSOKY = #{param.physoky}
