/* updateWrcvitForPhysical */
UPDATE ${userData.schema}.WRCVIT
	SET RCVITST = #{param.rcvitst},
		LMODATE = DATE_FORMAT(NOW(), '%Y%m%d'),
		LMOTIME = DATE_FORMAT(NOW(), '%H%i%s'),
		LMOUSER = #{userData.useract},
		UPDTCHK = UPDTCHK + 1
WHERE
	WAREKEY = #{param.warekey}
	AND RCVDCKY = #{param.rcvdcky}
	AND RCVDCIT = #{param.rcvdcit}
	AND SKUMKEY = #{param.skumkey}

mapper.insert:
/* insertWphyitForInvoiceChange */ INSERT INTO ${userData.schema}.WPHYIT(
PHYSOKY, PHYSOIT,
WAREKEY, DOCCATE, DOCTYPE, PHYNAME, PHYSTAT, PHYMODE, PHYGRKY, STOCKKY, LOTNMKY, AREAKEY, LOCAKEY, STLAYER, CUSTCOD, CUSTNAM, OWNERKY, OWNRNAM, FNCUSKY, PARSNCD, PARSNNM, BTRCATE, BTRFSTC, SKUGRKY, SKUMKEY, SKUDESC, ADDCOKY, ITEMCOD, PURCNUM, ORDERLN, SKUWEIG, SKUWIDT, SKULENG, SKUTHIC, GROSSWG, GROSSLN, GROSSWD, GROSSTH, REGIORG, REGIMOD, DESTORG, DEORGNM, DESTMOD, DEMODNM, DEMDMAN, DEMPOCD, DEMDADR, DEMDTLN, POSHPDT, POSHPTM, POSHPDY, SHPLIMT, DELVDSR, STKMEMO, EMSKUYN, RCVDCDT, RCVDCTM, SUOMKEY, RCVDCKY, RCVDCIT, SYSTQTY, PHYSQTY, COMPQTY,
CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER ) SELECT
#{param.physoky} AS PHYSOKY, ${userData.schema}.FN_SM_PHYSOIT(#{param.physoky}) AS PHYSOIT,
WST.WAREKEY, #{param.doccate} AS DOCCATE, #{param.doctype} AS DOCTYPE, CONCAT(date_format(now(), '%Y%m%d'), '_실사_', '송장수정') AS PHYNAME, #{param.phystat} AS PHYSTAT, #{param.phymode} AS PHYMODE, #{param.phygrky} AS PHYGRKY, WST.STOCKKY, WST.LOTNMKY, WST.AREAKEY, WST.LOCAKEY, WST.LOLAYER, WST.CUSTCOD, WST.CUSTNAM, WST.OWNERKY, WST.OWNRNAM, IFNULL(WST.FNCUSKY, ''), #{param.parsncd} AS PARSNCD, #{param.parsnnm} AS PARSNNM, WST.BTRCATE, IFNULL(WST.BTRFSTC, ''), WST.SKUGRKY, WST.SKUMKEY, WST.SKUDESC, WST.ADDCOKY, WST.ITEMCOD, WST.PURCNUM, WST.ORDERLN, WST.SKUWEIG, WST.SKUWIDT, WST.SKULENG, WST.SKUTHIC, WST.GROSSWG, WST.GROSSLN, WST.GROSSWD, WST.GROSSTH, WST.REGIORG, WST.REGIMOD, IFNULL(WST.DESTORG, ''), WST.DEORGNM, IFNULL(WST.DESTMOD, ''), WST.DEMODNM, IFNULL(WST.DEMDMAN, ''), IFNULL(WST.DEMPOCD, ''), IFNULL(WST.DEMDADR, ''), IFNULL(WST.DEMDTLN, ''), REPLACE(WST.POSHPDT, '-', ''), REPLACE(WST.POSHPTM, ':', ''), WST.POSHPDY, REPLACE(WST.SHPLIMT, '-', ''), REPLACE(WST.DELVDSR, '-', ''), WST.STKMEMO, WST.EMSKUYN, REPLACE(WST.RCVDCDT, '-', ''), REPLACE(WST.RCVDCTM, ':', ''), WST.SUOMKEY, WST.RCVDCKY, WST.RCVDCIT, #{param.systqty} AS SYSTQTY, #{param.physqty} AS PHYSQTY, #{param.compqty} AS COMPQTY,
date_format(now(), '%Y%m%d') AS CREDATE, date_format(now(), '%H%i%s') AS CRETIME, #{userData.useract} AS CREUSER, date_format(now(), '%Y%m%d') AS LMODATE, date_format(now(), '%H%i%s') AS LMOTIME, #{userData.useract} AS LMOUSER FROM ${userData.schema}.WSTKKY WST WHERE WST.WAREKEY = #{param.warekey}
AND WST.STOCKKY = #{param.stockky}
AND WST.SKUMKEY = #{param.skumkey}

mapper.select:
/* selectWtakitListForValidation */ SELECT
WTK.TASKOKY, WTK.TASKOIT,
WTK.WAREKEY, WTK.TASKDAT, WTK.DOCCATE, WTK.DOCTYPE, WTK.TASKSTS, WTK.LOTNMKY, OWNRNAM, WTK.OWNERKY, WTK.CUSTCOD, WTK.CUSTNAM, WTK.SKUMKEY, WTK.SKUDESC, WTK.FRAREKY, WTK.FRLOCKY, WTK.FRLAYER, WTK.TOAREKY, WTK.TOLOCKY, WTK.TOLAYER, WTK.EQUIPKY, WTK.FORDQTY, WTK.TCMPQTY, WTK.ALLGRKY, WTK.MVSTDAT, WTK.MVSTTIM, WTK.MVEDDAT, WTK.MVEDTIM, WTK.PARSNCD, WTK.PARSNNM, WTK.PKRSNCD, WTK.PKRSNNM, WTK.STOCKKY, WTK.PLNSIZE, WTK.EOASNKY, WTK.EOASNIT, WTK.COSTRKY, WTK.COSTRIT, WTK.RCVDCKY, WTK.RCVDCIT, WTK.OUTBOKY, WTK.OUTBOIT, WTK.SHPDCKY, WTK.SHPDCIT, WTK.VHPLNKY, WTK.VHPLNIT,
WTK.CREDATE, WTK.CRETIME, WTK.CREUSER, WTK.LMODATE, WTK.LMOTIME, WTK.LMOUSER, WTK.UPDTCHK FROM ${userData.schema}.WTAKIT WTK WHERE WTK.WAREKEY = #{param.warekey} AND WTK.SHPDCKY = #{param.shpdcky}
